  ('social-worker-moex-01321', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「協助個體會克服因為性別歧視而導致的社會問題」是女性主義社會工作取向，下列何者不是女 性主義社會工作觀點？', '["認為「我們都是姊妹」的女性經驗是沒有差異的", "分析女性受壓迫與不公平對待的原因", "致力於將女性私領域的困境轉為公共化", "檢視系統性的性別歧視"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
